using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictionResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationResult
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public IReadOnlyList<CategoryMetric> PerCategory { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[]? _categoryLabels;
    private readonly Lock _lock = new();

    public bool IsTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 0);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    }

    public EvaluationResult TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and build the pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate on the full dataset (small dataset, so split would be unreliable)
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        // Train on full data for the production model
        var model = pipeline.Fit(dataView);

        lock (_lock)
        {
            _model = model;
            _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

            // Extract the ordered label names from the key-value mapping
            var labelCol = dataView.Schema["Category"];
            var slotNames = new VBuffer<ReadOnlyMemory<char>>();

            // Get labels from the trained model's Label column
            var transformedData = _model.Transform(dataView);
            var labelColumn = transformedData.Schema["Label"];
            labelColumn.GetKeyValues(ref slotNames);
            _categoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        }

        // Aggregate cross-validation metrics
        var metrics = cvResults.Select(r => r.Metrics).ToList();
        var avgMacro = metrics.Average(m => m.MacroAccuracy);
        var avgMicro = metrics.Average(m => m.MicroAccuracy);
        var avgLogLoss = metrics.Average(m => m.LogLoss);
        var avgLogLossReduction = metrics.Average(m => m.LogLossReduction);

        // Per-category metrics from the last fold's confusion matrix
        var lastMetrics = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First().Metrics;
        var perCategory = new List<CategoryMetric>();
        var confusionMatrix = lastMetrics.ConfusionMatrix;
        for (int i = 0; i < confusionMatrix.PerClassPrecision.Count; i++)
        {
            perCategory.Add(new CategoryMetric
            {
                Category = _categoryLabels is not null && i < _categoryLabels.Length
                    ? _categoryLabels[i] : $"Class {i}",
                Precision = confusionMatrix.PerClassPrecision[i],
                Recall = confusionMatrix.PerClassRecall[i],
                F1Score = 2 * (confusionMatrix.PerClassPrecision[i] * confusionMatrix.PerClassRecall[i])
                    / (confusionMatrix.PerClassPrecision[i] + confusionMatrix.PerClassRecall[i])
            });
        }

        return new EvaluationResult
        {
            MacroAccuracy = avgMacro,
            MicroAccuracy = avgMicro,
            LogLoss = avgLogLoss,
            LogLossReduction = avgLogLossReduction,
            PerCategory = perCategory
        };
    }

    public PredictionResult Predict(TicketRequest request)
    {
        lock (_lock)
        {
            if (_predictionEngine is null || _categoryLabels is null)
                throw new InvalidOperationException(
                    "Model has not been trained. Call POST /api/tickets/train first.");

            var prediction = _predictionEngine.Predict(new TicketData
            {
                Subject = request.Subject,
                Description = request.Description,
                Priority = request.Priority
            });

            var confidence = new Dictionary<string, float>();
            for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
            {
                confidence[_categoryLabels[i]] = prediction.Score[i];
            }

            return new PredictionResult
            {
                PredictedCategory = prediction.PredictedCategory,
                Confidence = confidence
            };
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Trains the ML model on the CSV data and returns evaluation metrics.
    /// </summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResult> Train()
    {
        var result = _classifier.TrainAndEvaluate();
        return Ok(result);
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<PredictionResult> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        if (!_classifier.IsTrained)
            return BadRequest("Model has not been trained. Call POST /api/tickets/train first.");

        var result = _classifier.Predict(request);
        return Ok(result);
    }
}

