                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate on the full dataset (small dataset, so split would be unreliable)
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        // Train on full data for the production model
        var model = pipeline.Fit(dataView);

        lock (_lock)
        {
            _model = model;
            _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

            // Extract the ordered label names from the key-value mapping
            var slotNames = new VBuffer<ReadOnlyMemory<char>>();
            var transformedData = _model.Transform(dataView);
            var labelColumn = transformedData.Schema["Label"];
            labelColumn.GetKeyValues(ref slotNames);
            _categoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        }

        // Aggregate cross-validation metrics
        var metrics = cvResults.Select(r => r.Metrics).ToList();
        var avgMacro = metrics.Average(m => m.MacroAccuracy);
        var avgMicro = metrics.Average(m => m.MicroAccuracy);
        var avgLogLoss = metrics.Average(m => m.LogLoss);
        var avgLogLossReduction = metrics.Average(m => m.LogLossReduction);

        // Per-category metrics from the best fold's confusion matrix
        var bestMetrics = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First().Metrics;
